    label,
    variant,
    size,
    disabled
  };
}

// All defaults applied
const btn1 = Button({ label: 'Click Me' });
console.log(btn1.label + ' | ' + btn1.variant + ' | ' + btn1.size + ' | ' + btn1.disabled);

