const todos = [
  { id: 1, text: 'Learn React', done: false },
  { id: 2, text: 'Practice hooks', done: false }
];

function addItem(arr, newItem) {
  return [...arr, newItem];
}

function removeItem(arr, id) {
  return arr.filter(item => item.id !== id);
}

function toggleItem(arr, id) {
  return arr.map(item =>
    item.id === id ? { ...item, done: !item.done } : item
  );
}

const added = addItem(todos, { id: 3, text: 'Build project', done: false });
console.log('Added: ' + added.map(t => t.text).join(', '));

const removed = removeItem(todos, 1);
console.log('Removed: ' + removed.map(t => t.text).join(', '));

const toggled = toggleItem(todos, 2);
console.log('Toggled: ' + toggled[1].text + ' done=' + toggled[1].done);

console.log('Original intact: ' + todos.length + ' items, todo2 done=' + todos[1].done);

