function kmToMiles(km) { return km * 0.621371; }
function milesToKm(miles) { return miles / 0.621371; }

function KmInput(props) {
  return 'KM: ' + props.value.toFixed(2);
}

function MilesInput(props) {
  return 'Miles: ' + props.value.toFixed(2);
}

function Converter() {
  let distance = 0;
  let unit = 'km';

  function handleKmChange(value) {
    distance = value;
    unit = 'km';
  }

  function handleMilesChange(value) {
    distance = value;
    unit = 'miles';
  }

  // Enter 100 km
  handleKmChange(100);
  let km = unit === 'km' ? distance : milesToKm(distance);
  let miles = unit === 'miles' ? distance : kmToMiles(distance);
  console.log(KmInput({ value: km }));
  console.log(MilesInput({ value: miles }));

  // Enter 50 miles
  handleMilesChange(50);
  km = unit === 'km' ? distance : milesToKm(distance);
  miles = unit === 'miles' ? distance : kmToMiles(distance);
  console.log(KmInput({ value: km }));
  console.log(MilesInput({ value: miles }));
}

Converter();
